/**
 * SkillSystem — Skill tree management, point spending, and AoE shapes.
 * @module SkillSystem
 */

import DebugLog from '../debug/DebugLog.js';
import TREES_DATA from '../data/skill_trees.json';
import CharacterSystem from './CharacterSystem.js';

// Level requirements per tier
const TIER_MIN_LEVEL = { 1: 1, 2: 4, 3: 8, 4: 12, 5: 16 };
// Points needed in previous tier to unlock next
const TIER_REQUIRED_POINTS = { 2: 2, 3: 4, 4: 6, 5: 8 };

const SkillSystem = {
  _trees: null,
  _treeMap: null,

  init() {
    this._trees = TREES_DATA;
    this._treeMap = new Map(TREES_DATA.map(t => [t.id, t]));
    DebugLog.info(`[skill] SkillSystem initialized; trees=${TREES_DATA.length}`);
  },

  getTreeById(treeId) {
    if (!this._treeMap) this.init();
    return this._treeMap.get(treeId) ?? null;
  },

  getSkillById(treeId, skillId) {
    const tree = this.getTreeById(treeId);
    return tree?.skills?.find(s => s.id === skillId) ?? null;
  },

  getAllTrees() {
    if (!this._trees) this.init();
    return this._trees;
  },

  getTierPointsSpent(character, treeId, tier) {
    const skills = character.skills?.[treeId] ?? {};
    const tree = this.getTreeById(treeId);
    if (!tree) return 0;
    return (tree.skills ?? [])
      .filter(s => s.tier === tier)
      .reduce((sum, s) => sum + (skills[s.id] ?? 0), 0);
  },

  canLearnSkill(character, treeId, skillId) {
    if (!this._trees) this.init();
    const tree = this.getTreeById(treeId);
    if (!tree) return { canLearn: false, reason: 'Unknown tree.' };

    const skill = this.getSkillById(treeId, skillId);
    if (!skill) return { canLearn: false, reason: 'Unknown skill.' };

    // Must have the tree selected
    const selectedTrees = character.skillTrees ?? [];
    if (!selectedTrees.includes(treeId)) {
      return { canLearn: false, reason: `Must have ${tree.name} tree selected.` };
    }

    // Must have skill points
    if ((character.skillPoints ?? 0) < 1) {
      return { canLearn: false, reason: 'No skill points available.' };
    }

    // Level requirement
    const minLevel = TIER_MIN_LEVEL[skill.tier] ?? 1;
    if ((character.level ?? 1) < minLevel) {
      return { canLearn: false, reason: `Requires level ${minLevel}.` };
    }

    // Tier unlock: need enough points in previous tier
    if (skill.tier > 1) {
      const needed = TIER_REQUIRED_POINTS[skill.tier] ?? 0;
      const spent = this.getTierPointsSpent(character, treeId, skill.tier - 1);
      if (spent < needed) {
        return { canLearn: false, reason: `Requires ${needed} points in Tier ${skill.tier - 1} (have ${spent}).` };
      }
    }

    // Already at max level?
    const current = character.skills?.[treeId]?.[skillId] ?? 0;
    if (current >= (skill.maxLevel ?? 5)) {
      return { canLearn: false, reason: 'Already at maximum level.' };
    }

    return { canLearn: true, reason: '' };
  },

  spendPoint(character, treeId, skillId) {
    const { canLearn, reason } = this.canLearnSkill(character, treeId, skillId);
    if (!canLearn) return { success: false, message: reason };

    if (!character.skills) character.skills = {};
    if (!character.skills[treeId]) character.skills[treeId] = {};
    character.skills[treeId][skillId] = (character.skills[treeId][skillId] ?? 0) + 1;
    character.skillPoints = (character.skillPoints ?? 0) - 1;

    // Recompute class
    const spent = {};
    for (const tid of (character.skillTrees ?? [])) {
      const pts = Object.values(character.skills[tid] ?? {}).reduce((s, v) => s + v, 0);
      spent[tid] = pts;
    }
    const topTrees = Object.entries(spent).sort((a,b) => b[1]-a[1]).slice(0,3).map(([id]) => id);
    character.className = CharacterSystem.computeClass(topTrees);

    DebugLog.info(`[skill] ${character.name} learned ${skillId} (${treeId}) lv${character.skills[treeId][skillId]}; sp=${character.skillPoints}`);
    return { success: true, message: `Learned ${skillId} (level ${character.skills[treeId][skillId]}).` };
  },

  getCharacterSkills(character) {
    const result = [];
    for (const treeId of Object.keys(character.skills ?? {})) {
      const tree = this.getTreeById(treeId);
      for (const [skillId, level] of Object.entries(character.skills[treeId])) {
        const skill = this.getSkillById(treeId, skillId);
        result.push({ tree, skill, treeId, skillId, level });
      }
    }
    return result;
  },

  getAoEShape(skill) {
    const type = skill?.targetingType ?? 'single';
    switch (type) {
      case 'single': return [];
      case 'self': return [];
      case 'aoe_adjacent': return [{dx:0,dy:0},{dx:1,dy:0},{dx:-1,dy:0},{dx:0,dy:1},{dx:0,dy:-1}];
      case 'aoe_row': return [-3,-2,-1,0,1,2,3].map(dx => ({dx, dy:0}));
      case 'aoe_col': return [-2,-1,0,1,2].map(dy => ({dx:0, dy}));
      case 'aoe_zone_3x3': {
        const cells = [];
        for (let dx=-1;dx<=1;dx++) for (let dy=-1;dy<=1;dy++) cells.push({dx,dy});
        return cells;
      }
      case 'aoe_cone': return [{dx:0,dy:0},{dx:1,dy:-1},{dx:1,dy:1}];
      case 'aoe_line': return [{dx:0,dy:0},{dx:1,dy:0},{dx:2,dy:0},{dx:3,dy:0}];
      case 'aoe_chain': return [{dx:0,dy:0}]; // runtime: bounces to nearest
      case 'aoe_all_enemies': return [{dx:0,dy:0}]; // runtime: all enemy tiles
      case 'aoe_all_allies': return [{dx:0,dy:0}]; // runtime: all ally tiles
      case 'party': return [];
      default: return [];
    }
  },

  getSkillDamageDescription(skill, level) {
    if (!skill) return '';
    const idx = Math.max(0, (level ?? 1) - 1);
    const mult = Array.isArray(skill.damageMultiplier) ? skill.damageMultiplier[idx] : null;
    const flatDmg = Array.isArray(skill.flatDamage) ? skill.flatDamage[idx] : null;
    const src = skill.damageSource ?? 'weapon';
    if (mult) return `${mult}x ${src} damage`;
    if (flatDmg) return `${flatDmg} ${src} damage`;
    if (skill.isPassive) return 'Passive effect';
    return skill.description ?? '';
  },

  getActiveAura(character) {
    return character?.activeAura ?? null;
  },

  getEquippedPartySkill(character) {
    return character?.partySkill ?? null;
  },

  equipPartySkill(character, treeId, skillId) {
    const skill = this.getSkillById(treeId, skillId);
    if (!skill?.isPartySkill) return { success: false, message: 'Not a party skill.' };
    const known = character.skills?.[treeId]?.[skillId] ?? 0;
    if (known < 1) return { success: false, message: 'Skill not learned.' };
    character.partySkill = { treeId, skillId };
    return { success: true, message: `Party skill set: ${skill.name}` };
  },
};

export default SkillSystem;
